mutation CalapresCreateSupplierMetafieldDefinition($definition: MetafieldDefinitionInput!) {
  metafieldDefinitionCreate(definition: $definition) {
    createdDefinition {
      id
      name
      namespace
      key
      ownerType
      pinnedPosition
      type {
        name
      }
      access {
        admin
      }
      capabilities {
        adminFilterable {
          eligible
          enabled
          status
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

